func contactDisplay(c models.Contact) string {
	if c.Name != "" {
		return c.Name
	}
	return c.Email
}

func threadAwareAction(singleFn, threadFn string, email *models.Email) string {
	if email.ThreadCount > 1 {
		return fmt.Sprintf("%s('%s')", threadFn, email.ID)
	}
	return fmt.Sprintf("%s('%s')", singleFn, email.ID)
}

func threadAwareLabel(single, thread string, email *models.Email) string {
	if email.ThreadCount > 1 {
		return thread
	}
	return single
}

func formatContacts(contacts []models.Contact) string {
	parts := make([]string, len(contacts))
	for i, c := range contacts {
		if c.Name != "" {
			parts[i] = fmt.Sprintf("%s <%s>", c.Name, c.Email)
		} else {
			parts[i] = c.Email
		}
	}
	return strings.Join(parts, ", ")
}

